mapper.select:
${pagingTop} SELECT HOMEPAGE_ID, SUPPORT_IDX, SUPPORT_STATUS, AREA_CODE, SCHOOL_NAME, SUPPORT_REQ_FIRST, SUPPORT_REQ_SECOND, FIRST_START_DATE, FIRST_END_DATE, SECOND_START_DATE, SECOND_END_DATE, SUPPORT_REQ_DESC, MEMBER_POSITION, MEMBER_ID, MEMBER_KEY, MEMBER_NAME, MEMBER_PHONE, MEMBER_CELL_PHONE, TOTAL_BOOK_COUNT, PROGRAM_NAME, PERCENT, PARENT_COUNT, STAFF_COUNT, MANAGER_COUNT, MANAGER_TYPE, ADD_DATE, ADD_ID, MOD_DATE, MOD_ID, DELETE_YN FROM SCHOOL_SUPPORT WHERE HOMEPAGE_ID = #{homepage_id} AND DELETE_YN = 'N' AND SUPPORT_STATUS = #{support_status} AND (FIRST_START_DATE like #{support_year}||'%' OR FIRST_END_DATE like #{support_year}||'%' OR SECOND_START_DATE like #{support_year}||'%' OR SECOND_END_DATE like #{support_year}||'%')
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY ADD_DATE ${pagingBottom}

mapper.update:
UPDATE SCHOOL_SUPPORT SET SUPPORT_STATUS = #{support_status}, AREA_CODE = #{area_code}, SCHOOL_NAME = #{school_name}, SUPPORT_REQ_FIRST = #{support_req_first},
FIRST_START_DATE = #{first_start_date}, FIRST_END_DATE = #{first_end_date},
